1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result.sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]].sort());
17	  });
18	  it("should keep a live cell alive when it has 3 neighbors (survival)", () => {
19	    // Cell (1,0) has 3 live neighbors: (0,0), (2,0), (1,1) → survives
20	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
21	    expect(result).toContainEqual([1, 0]);
22	  });
23	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
24	    // Cell (1,1) has 4 live neighbors: (0,0), (2,0), (0,2), (2,2) → dies
25	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
26	    expect(result).not.toContainEqual([1, 1]);
27	  });
28	  it("should keep a block pattern stable (still life)", () => {
29	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
30	    const result = nextGeneration(block);
31	    expect(result.sort()).toEqual(block.sort());
32	  });
33	  it("should oscillate a blinker pattern", () => {
34	    // Vertical blinker → horizontal blinker
35	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
36	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
37	    const gen1 = nextGeneration(vertical);
38	    expect(gen1.sort()).toEqual(horizontal.sort());
39	    // Horizontal blinker → back to vertical
40	    const gen2 = nextGeneration(gen1);
41	    expect(gen2.sort()).toEqual(vertical.sort());
42	  });
43	});
